VALUES ('BACK_END','BIZ_AGENT_WELCOME_TITLE_8100','hi-IN','ओक्सपोर्ट एफिलिएट प्रोग्राम में आपका स्वागत है',20241123065530,NULL,NULL,NULL);

VALUES ('BACK_END','BIZ_AGENT_WELCOME_CONTENT_8100','hi-IN','प्रिय %s: भागीदार के रूप में %s में आपका स्वागत है! क्या आप दूसरों से पहले सर्वश्रेष्ठ संसाधन चैनलों तक पहुँच प्राप्त करना चाहते हैं? क्या आप कस्टम हाई-एंड सेवाएँ चाहते हैं? क्या आप नवीनतम और उच्चतम-गुणवत्ता वाले सहायता कार्यक्रमों की तलाश कर रहे हैं? जल्दी करें और अपने 24/7 सहबद्ध ऑनलाइन ग्राहक सेवा से संपर्क करें। हम आपको सबसे अधिक आधिकारिक सहायता प्रदान करने के लिए प्रतिबद्ध हैं~',20241123065530,NULL,NULL,NULL);

