VALUES ('BACK_END','BIZ_AGENT_FUNDS_SECURITY_TITLE_8100','hi-IN','निधि सुरक्षा अधिसूचना',20241123065531,NULL,NULL,NULL);

-- 代理资金安全通知内容
VALUES ('BACK_END','BIZ_AGENT_FUNDS_SECURITY_CONTENT_8100','hi-IN','प्रिय भागीदार: अपने धन की सुरक्षा के लिए, कृपया %s के कर्मचारी होने का दावा करने वाले किसी भी व्यक्ति पर भरोसा न करें जो सदस्यों से वास्तव में धन प्राप्त किए बिना लेनदेन की पुष्टि करने के लिए कहता है। याद रखें कि अपने खाते का पासवर्ड दूसरों को न बताएं या खाता किराए पर देने या बेचने में संलग्न न हों, %s प्लेटफ़ॉर्म कभी भी भागीदारों से ईमेल के माध्यम से धन हस्तांतरित करने का अनुरोध नहीं करेगा! उपरोक्त सभी हैकर हैं। एक बार जानकारी प्रदान करने के बाद, इसे संशोधित किया जाएगा, जिसके परिणामस्वरूप वित्तीय नुकसान होगा मुखबिर आधिकारिक टीम से पुरस्कार के लिए प्रतिक्रिया अनुभाग में सुराग प्रदान कर सकते हैं। यदि आपके कोई प्रश्न हैं, तो कृपया हमारी 24/7 सहबद्ध ऑनलाइन ग्राहक सेवा से संपर्क करें~',20241123065531,NULL,NULL,NULL);



