INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_WELCOME_TITLE_8100','hi-IN','%s में आपका स्वागत है',20241123065528,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_WELCOME_CONTENT_8100','hi-IN','प्रिय %s: %s का आधिकारिक सदस्य बनने पर बधाई। %s चुनने से आपके खाते और धन की सुरक्षा सुनिश्चित होगी। हम आपको दुनिया के शीर्ष खेल आयोजनों, लाइव कैसीनो, पोकर गेम, स्लॉट और बहुत कुछ प्रदान करते हैं। हम अत्यधिक सुविधाजनक जमा और निकासी विकल्प भी प्रदान करते हैं, जिससे आप चिंता मुक्त लेनदेन का अनुभव कर सकते हैं।',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_DEPOSIT_SUCCESS_TITLE_8100','hi-IN','जमा सफलता अधिसूचना',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_DEPOSIT_SUCCESS_CONTENT_8100','hi-IN','प्रिय %s: {%s %s राशि} की सफल जमा पर बधाई~',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_WITHDRAWAL_SUCCESS_TITLE_8100','hi-IN','निकासी सफलता अधिसूचना',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_WITHDRAWAL_SUCCESS_CONTENT_8100','hi-IN','प्रिय %s: %s %s की सफल निकासी पर बधाई~',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_WITHDRAWAL_FAILED_TITLE_8100','hi-IN','निकासी विफलता अधिसूचना',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_WITHDRAWAL_FAILED_CONTENT_8100','hi-IN','प्रिय %s: हमें आपको यह बताते हुए खेद है कि आपकी निकासी विफल हो गई है! यदि आपके कोई प्रश्न हैं, तो कृपया हमारी 24/7 ऑनलाइन ग्राहक सेवा से संपर्क करें~',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_SECURITY_TITLE_8100','hi-IN','सुरक्षा अधिसूचना',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_SECURITY_CONTENT_8100','hi-IN','प्रिय ग्राहक: अपने खाते की सुरक्षा के लिए, यदि आपके पास जमा/निकासी के बारे में कोई प्रश्न है, तो कृपया हमारी ऑनलाइन ग्राहक सेवा से संपर्क करें और निजी लेनदेन में शामिल न हों! यदि आपके पास कोई प्रश्न है, तो कृपया हमारी 24/7 ऑनलाइन ग्राहक सेवा से संपर्क करें~',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_FUNDS_SECURITY_TITLE_8100','hi-IN','निधि सुरक्षा अधिसूचना',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_FUNDS_SECURITY_CONTENT_8100','hi-IN','प्रिय ग्राहक: अपने धन की सुरक्षा के लिए, कृपया %s के कर्मचारी होने का दावा करने वाले किसी भी व्यक्ति पर भरोसा न करें जो सदस्यों से वास्तव में धन प्राप्त किए बिना लेनदेन की पुष्टि करने के लिए कहता है। याद रखें कि अपने खाते का पासवर्ड दूसरों को न बताएं या खाता किराए पर देने या बेचने में संलग्न न हों, {oksport} प्लेटफ़ॉर्म कभी भी सदस्यों से ईमेल के माध्यम से धन हस्तांतरित करने का अनुरोध नहीं करेगा! उपरोक्त सभी हैकर हैं। एक बार जानकारी प्रदान करने के बाद, इसे संशोधित किया जाएगा, जिसके परिणामस्वरूप वित्तीय नुकसान होगा। मुखबिर आधिकारिक टीम से पुरस्कार के लिए प्रतिक्रिया अनुभाग में सुराग प्रदान कर सकते हैं। यदि आपके कोई प्रश्न हैं, तो कृपया हमारी 24/7 ऑनलाइन ग्राहक सेवा से संपर्क करें~',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_VERSION_UPGRADE_TITLE_8100','hi-IN','संस्करण अपग्रेड अधिसूचना',20241123065529,NULL,NULL,NULL);
INSERT INTO i18n_message (`message_type`,`message_key`,`language`,`message`,`created_time`,`updated_time`,`creator`,`updater`) VALUES ('BACK_END','BIZ_MEMBER_VERSION_UPGRADE_CONTENT_8100','hi-IN','प्रिय ग्राहक: एक नया संस्करण अपडेट के लिए उपलब्ध है। बेहतर अनुभव के लिए, कृपया अपडेट करने के लिए आगे बढ़ें~',20241123065529,NULL,NULL,NULL);
